#include <mpi.h>
#include <omp.h>
#include <vector>
#include <cmath>
#include <algorithm>

struct Point {
    double x, y;
};

double distance(Point const& p1, Point const& p2) {
    return std::sqrt(std::pow(p2.x - p1.x, 2) + std::pow(p2.y - p1.y, 2));
}

double closestPair(std::vector<Point> const& points) {
    int rank, size;
    MPI_Comm_rank(MPI_COMM_WORLD, &rank);
    MPI_Comm_size(MPI_COMM_WORLD, &size);

    // Divide the points equally among processes
    std::vector<Point> local_points(points.size() / size + (rank < points.size() % size));
    for (int i = 0; i < local_points.size(); ++i) {
        if (rank * local_points.size() + i < points.size()) {
            local_points[i] = points[rank * local_points.size() + i];
        }
    }

    // Compute the minimum distance within each process using OpenMP
    double min_dist_local = std::numeric_limits<double>::max();
    #pragma omp parallel for reduction(min: min_dist_local)
    for (int i = 0; i < local_points.size(); ++i) {
        for (int j = i + 1; j < local_points.size(); ++j) {
            double dist = distance(local_points[i], local_points[j]);
            if (dist < min_dist_local) {
                min_dist_local = dist;
            }
        }
    }

    // Gather the minimum distances from all processes
    std::vector<double> min_dists(size);
    MPI_Gather(&min_dist_local, 1, MPI_DOUBLE, &min_dists[0], 1, MPI_DOUBLE, 0, MPI_COMM_WORLD);

    if (rank == 0) {
        // Find the global minimum distance
        double min_dist_global = std::numeric_limits<double>::max();
        for (int i = 0; i < size; ++i) {
            if (min_dists[i] < min_dist_global) {
                min_dist_global = min_dists[i];
            }
        }

        return min_dist_global;
    } else {
        // Cleanup for non-root processes
        return 0.0;
    }
}
